"use client";

import { useEffect, useRef, useCallback } from "react";

const BUILDING_IMG = "";
const CLOUD_IMG    = "";
const OVERLAY_IMG  = "";

export default function LandingPage() {
  /* ── refs for DOM elements we animate directly (no re-render) ── */
  const skyRef        = useRef<HTMLDivElement>(null);
  const buildingRef   = useRef<HTMLDivElement>(null);
  const textRef       = useRef<HTMLDivElement>(null);
  const navRef        = useRef<HTMLDivElement>(null);
  const cloudLRef     = useRef<HTMLDivElement>(null);
  const cloudRRef     = useRef<HTMLDivElement>(null);
  const cloudBtmRef   = useRef<HTMLDivElement>(null);

  /* ── lerp loop ── */
  const lerpedScroll  = useRef(0);
  const targetScroll  = useRef(0);
  const rafId         = useRef<number>(0);
  const isRunning     = useRef(false);

  const lerp = (a: number, b: number, t: number) => a + (b - a) * t;

  const tick = useCallback(() => {
    const prev = lerpedScroll.current;
    lerpedScroll.current = lerp(prev, targetScroll.current, 0.068);

    const s   = lerpedScroll.current;
    const vh  = window.innerHeight;

    /* progress 0→1 over 1.5 viewports */
    const raw = Math.min(s / (vh * 1.3), 1);
    /* ease-out cubic */
    const p   = 1 - Math.pow(1 - raw, 3);

    /* ── SKY parallax ── */
    if (skyRef.current) {
      skyRef.current.style.transform =
        `translateY(${p * 55}px) scale(${1 + p * 0.05})`;
    }

    /* ── BUILDING: scale 1→1.28 AND translateY upward strongly ── */
    if (buildingRef.current) {
      const scale = 1 + p * 0.28;           // grows 28%
      const ty    = -p * 45;                 // moves up 45vh
      buildingRef.current.style.transform =
        `translateX(-50%) translateY(${ty}vh) scale(${scale})`;
    }

    /* ── TEXT fade + lift ── */
    const textP = Math.max(1 - raw * 3.2, 0);
    if (textRef.current) {
      textRef.current.style.opacity   = String(textP);
      textRef.current.style.transform = `translateY(${-p * 60}px)`;
    }
    if (navRef.current) {
      navRef.current.style.opacity = String(textP);
    }

    /* ── FOREGROUND CLOUDS sweep in ── */
    const cRaw  = Math.min(raw * 1.6, 1);
    const cP    = 1 - Math.pow(1 - cRaw, 3);
    const cOp   = cP;
    if (cloudLRef.current) {
      cloudLRef.current.style.opacity   = String(cOp);
      cloudLRef.current.style.transform = `translateX(${(1 - cP) * -380}px)`;
    }
    if (cloudRRef.current) {
      cloudRRef.current.style.opacity   = String(cOp);
      cloudRRef.current.style.transform = `translateX(${(1 - cP) * 380}px)`;
    }

    /* ── BOTTOM CLOUD rises up ── */
    const bRaw = Math.min(raw * 2.2, 1);
    const bP   = 1 - Math.pow(1 - bRaw, 3);
    if (cloudBtmRef.current) {
      cloudBtmRef.current.style.opacity   = String(bP);
      cloudBtmRef.current.style.transform =
        `translateX(-50%) translateY(${(1 - bP) * 180}px)`;
    }

    /* continue loop until settled */
    if (Math.abs(lerpedScroll.current - targetScroll.current) > 0.25) {
      rafId.current = requestAnimationFrame(tick);
    } else {
      lerpedScroll.current = targetScroll.current;
      isRunning.current    = false;
    }
  }, []);

  useEffect(() => {
    const onScroll = () => {
      targetScroll.current = window.scrollY;
      if (!isRunning.current) {
        isRunning.current = true;
        rafId.current = requestAnimationFrame(tick);
      }
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => {
      window.removeEventListener("scroll", onScroll);
      cancelAnimationFrame(rafId.current);
    };
  }, [tick]);

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        html { scroll-behavior: auto; }
        body { overflow-x: hidden; background: #fff; }

        .hero-btn {
          background: rgba(8,8,8,0.86);
          backdrop-filter: blur(12px);
          -webkit-backdrop-filter: blur(12px);
          color: #fff;
          border: 1px solid rgba(255,255,255,0.12);
          border-radius: 999px;
          padding: 15px 32px;
          font-size: 1rem;
          font-weight: 600;
          cursor: pointer;
          display: inline-flex;
          align-items: center;
          gap: 10px;
          font-family: 'Inter', sans-serif;
          letter-spacing: 0.02em;
          transition: background 0.25s ease, transform 0.2s ease, box-shadow 0.25s ease;
          box-shadow: 0 8px 32px rgba(0,0,0,0.22), 0 2px 8px rgba(0,0,0,0.12);
        }
        .hero-btn:hover {
          background: rgba(0,0,0,0.96);
          transform: scale(1.04) translateY(-1px);
          box-shadow: 0 12px 40px rgba(0,0,0,0.28);
        }
        .nav-link {
          cursor: pointer;
          opacity: 0.82;
          transition: opacity 0.15s;
          display: flex; align-items: center; gap: 3px;
          font-size: 0.9rem;
        }
        .nav-link:hover { opacity: 1; }
        .signin-btn {
          background: #0d0d0d;
          color: #fff;
          border: none;
          border-radius: 999px;
          padding: 10px 26px;
          font-size: 0.9rem;
          font-weight: 600;
          cursor: pointer;
          font-family: 'Inter', sans-serif;
          transition: background 0.2s, transform 0.15s;
          box-shadow: 0 4px 16px rgba(0,0,0,0.2);
        }
        .signin-btn:hover { background: #333; transform: scale(1.03); }
        @media (max-width: 768px) {
          .hero-nav-links { display: none !important; }
          .hero-title { font-size: 12.5vw !important; line-height: 0.92 !important; }
        }
      `}</style>

      {/* ── SCROLL SPACER ── */}
      <div style={{ height: "280vh" }}>

        {/* ── STICKY HERO ── */}
        <div style={{
          position: "sticky", top: 0,
          height: "100vh", width: "100%",
          overflow: "hidden",
          backgroundColor: "#aec8df",
        }}>

          {/* 1. SKY BG */}
          <div ref={skyRef} style={{
            position: "absolute",
            inset: "-10% -5%",
            backgroundImage: `url(data:image/jpeg;base64,${CLOUD_IMG})`,
            backgroundSize: "cover",
            backgroundPosition: "center 18%",
            willChange: "transform",
            zIndex: 0,
            transformOrigin: "center top",
          }} />

          {/* 2. ATMOSPHERE GRADIENT */}
          <div style={{
            position: "absolute", inset: 0,
            background: "linear-gradient(180deg, rgba(160,200,235,0.0) 0%, rgba(160,200,235,0.0) 45%, rgba(180,215,242,0.28) 75%, rgba(205,228,248,0.5) 100%)",
            zIndex: 1, pointerEvents: "none",
          }} />

          {/* 3. BUILDING — full width, rises on scroll */}
          <div ref={buildingRef} style={{
            position: "absolute",
            bottom: 0,
            left: "50%",
            width: "100vw",
            transform: "translateX(-50%) translateY(0vh) scale(1)",
            transformOrigin: "center bottom",
            willChange: "transform",
            zIndex: 2,
            display: "flex",
            justifyContent: "center",
            alignItems: "flex-end",
          }}>
            <img
              src={`data:image/png;base64,${BUILDING_IMG}`}
              alt="Luxury building"
              style={{
                width: "100%",
                maxWidth: "1440px",
                height: "64vh",
                objectFit: "cover",
                objectPosition: "center top",
                display: "block",
              }}
            />
          </div>

          {/* 4. CLOUD OVERLAY — LEFT (real cloud image) */}
          <div ref={cloudLRef} style={{
            position: "absolute",
            left: "-20%",
            bottom: "2%",
            width: "65vw",
            minWidth: "400px",
            maxWidth: "900px",
            zIndex: 5,
            opacity: 0,
            transform: "translateX(-380px)",
            willChange: "transform, opacity",
            pointerEvents: "none",
          }}>
            <img
              src={`data:image/png;base64,${OVERLAY_IMG}`}
              alt=""
              style={{
                width: "100%", height: "auto", display: "block",
                transform: "scaleX(-1)",   /* mirror so it faces inward */
                filter: "brightness(1.08) contrast(0.92)",
              }}
            />
          </div>

          {/* 5. CLOUD OVERLAY — RIGHT (real cloud image) */}
          <div ref={cloudRRef} style={{
            position: "absolute",
            right: "-20%",
            bottom: "2%",
            width: "65vw",
            minWidth: "400px",
            maxWidth: "900px",
            zIndex: 5,
            opacity: 0,
            transform: "translateX(380px)",
            willChange: "transform, opacity",
            pointerEvents: "none",
          }}>
            <img
              src={`data:image/png;base64,${OVERLAY_IMG}`}
              alt=""
              style={{
                width: "100%", height: "auto", display: "block",
                filter: "brightness(1.08) contrast(0.92)",
              }}
            />
          </div>

          {/* 6. BOTTOM CLOUD SWEEP (real cloud image, wide) */}
          <div ref={cloudBtmRef} style={{
            position: "absolute",
            bottom: "-10%",
            left: "50%",
            width: "160%",
            transform: "translateX(-50%) translateY(180px)",
            zIndex: 6,
            opacity: 0,
            willChange: "transform, opacity",
            pointerEvents: "none",
          }}>
            <img
              src={`data:image/png;base64,${OVERLAY_IMG}`}
              alt=""
              style={{
                width: "100%", height: "auto", display: "block",
                filter: "brightness(1.12) contrast(0.88)",
              }}
            />
          </div>

          {/* 7. SUBTLE VIGNETTE */}
          <div style={{
            position: "absolute", inset: 0,
            background: "radial-gradient(ellipse at 50% 50%, transparent 50%, rgba(80,115,148,0.16) 100%)",
            zIndex: 7, pointerEvents: "none",
          }} />

          {/* 8. NAVBAR */}
          <nav ref={navRef} style={{
            position: "absolute", top: 0, left: 0, right: 0,
            zIndex: 10,
            display: "flex", alignItems: "center", justifyContent: "space-between",
            padding: "22px 48px",
            fontFamily: "'Inter', system-ui, sans-serif",
            willChange: "opacity",
          }}>
            <div style={{ fontWeight: 900, fontSize: "1.5rem", letterSpacing: "-0.04em", color: "#0a0a0a" }}>
              FIND
            </div>
            <div className="hero-nav-links" style={{ display: "flex", gap: "2rem", color: "#111", fontWeight: 500 }}>
              {["Search","Agents","Join"].map(item => (
                <span key={item} className="nav-link">{item}</span>
              ))}
              {["Paperwork","Resources","About"].map(item => (
                <span key={item} className="nav-link">
                  {item}
                  <svg width="11" height="11" viewBox="0 0 24 24" fill="none">
                    <path stroke="#111" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round" d="M6 9l6 6 6-6"/>
                  </svg>
                </span>
              ))}
            </div>
            <button className="signin-btn">Sign In</button>
          </nav>

          {/* 9. HERO TEXT */}
          <div ref={textRef} style={{
            position: "absolute",
            top: "14%", left: 0, right: 0,
            textAlign: "center",
            zIndex: 8,
            padding: "0 4vw",
            willChange: "transform, opacity",
            fontFamily: "'Inter', sans-serif",
          }}>
            <h1 className="hero-title" style={{
              fontSize: "clamp(2.8rem, 9vw, 7.8rem)",
              fontWeight: 900,
              color: "#0a0a0a",
              lineHeight: 0.94,
              letterSpacing: "-0.036em",
              margin: "0 0 1.3rem 0",
              textShadow: "0 1px 30px rgba(255,255,255,0.15)",
            }}>
              Find What Moves You
            </h1>
            <p style={{
              fontSize: "clamp(0.95rem, 1.55vw, 1.2rem)",
              color: "#1c1c1c",
              margin: "0 0 2.2rem 0",
              fontWeight: 400,
              letterSpacing: "0.005em",
            }}>
              <span style={{ fontWeight: 650 }}>Expert agents. Real guidance.</span>{" "}
              <span style={{ color: "#4a4a4a" }}>A clear path to find what's next.</span>
            </p>
            <button className="hero-btn">
              Find Properties
              <svg width="15" height="15" viewBox="0 0 24 24" fill="none">
                <path stroke="white" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round" d="M5 12h14M13 6l6 6-6 6"/>
              </svg>
            </button>
          </div>

        </div>
      </div>

      {/* ── PAGE CONTENT ── */}
      <div style={{ background: "#fff", padding: "8rem 2rem", textAlign: "center" }}>
        <h2 style={{
          fontFamily: "'Inter', sans-serif", fontWeight: 800,
          fontSize: "clamp(1.8rem, 4vw, 3rem)", color: "#0a0a0a",
          letterSpacing: "-0.03em", marginBottom: "1.2rem",
        }}>
          Why FIND
        </h2>
        <p style={{
          maxWidth: "580px", margin: "0 auto",
          color: "#555", lineHeight: 1.85, fontSize: "1.05rem",
          fontFamily: "'Inter', sans-serif",
        }}>
          Your life's changing. Don't just find a place — find what's next.
          We help you move forward with clarity, confidence, and the right agent by your side.
        </p>
      </div>
    </>
  );
}